  def validateCredentials(): Try[String] = {
    credentialManager.resolveCredentials().map { creds =>
      s"Credentials validated. Access Key ID: ${creds.accessKeyId().take(4)}****"
    }
  }

  def shutdown(): Unit = {
    Try(s3.close())
    Try(dynamoDb.close())
    Try(sqs.close())
  }
