object AwsServiceApp extends App {

  println("=== AWS Service Manager Demo ===")

  // Example 1: Using default credential chain
  val defaultManager = new AwsServiceManager(DefaultCredentials, Region.US_EAST_1)

  defaultManager.validateCredentials() match {
    case Success(msg) => println(s"Default credentials: $msg")
    case Failure(ex) => println(s"Default credentials failed: ${ex.getMessage}")
  }

  // Example 2: Using static credentials
  val staticManager = new AwsServiceManager(
    StaticCredentials("YOUR_ACCESS_KEY", "YOUR_SECRET_KEY"),
    Region.US_WEST_2
  )

  // Example 3: Using profile credentials
  val profileManager = new AwsServiceManager(
    ProfileCredentials("my-profile"),
    Region.EU_WEST_1
  )

  // Example 4: Using session credentials
  val sessionManager = new AwsServiceManager(
    SessionCredentials("ACCESS_KEY", "SECRET_KEY", "SESSION_TOKEN"),
    Region.AP_SOUTHEAST_1
  )

  // S3 operations demo
  println("\n--- S3 Operations ---")
  defaultManager.s3.listBuckets() match {
    case Success(buckets) =>
      println(s"Found ${buckets.size} buckets:")
      buckets.foreach(b => println(s"  - $b"))
    case Failure(ex) =>
      println(s"Failed to list buckets: ${ex.getMessage}")
  }

  // DynamoDB operations demo
  println("\n--- DynamoDB Operations ---")
  defaultManager.dynamoDb.listTables() match {
    case Success(tables) =>
      println(s"Found ${tables.size} tables:")
      tables.foreach(t => println(s"  - $t"))
    case Failure(ex) =>
      println(s"Failed to list tables: ${ex.getMessage}")
  }

  // SQS operations demo
  println("\n--- SQS Operations ---")
  defaultManager.sqs.listQueues() match {
    case Success(queues) =>
      println(s"Found ${queues.size} queues:")
      queues.foreach(q => println(s"  - $q"))
    case Failure(ex) =>
      println(s"Failed to list queues: ${ex.getMessage}")
  }

  // Full workflow example
  println("\n--- Full S3 Workflow ---")
  val bucketName = "my-test-bucket-" + System.currentTimeMillis()

  val s3Workflow = for {
    _ <- defaultManager.s3.createBucket(bucketName)
    _ = println(s"Created bucket: $bucketName")
    _ <- defaultManager.s3.putObject(bucketName, "test/hello.txt", "Hello, AWS!")
    _ = println("Uploaded object")
    content <- defaultManager.s3.getObject(bucketName, "test/hello.txt")
    _ = println(s"Retrieved content: $content")
    objects <- defaultManager.s3.listObjects(bucketName, Some("test/"))
    _ = println(s"Objects: ${objects.mkString(", ")}")
    _ <- defaultManager.s3.deleteObject(bucketName, "test/hello.txt")
    _ = println("Deleted object")
    _ <- defaultManager.s3.deleteBucket(bucketName)
    _ = println(s"Deleted bucket: $bucketName")
  } yield "S3 workflow completed successfully"

  s3Workflow match {
    case Success(msg) => println(msg)
    case Failure(ex) => println(s"S3 workflow failed: ${ex.getMessage}")
  }

  // DynamoDB workflow example
  println("\n--- Full DynamoDB Workflow ---")
  val tableName = "test-table-" + System.currentTimeMillis()

  val dynamoWorkflow = for {
    _ <- defaultManager.dynamoDb.createTable(tableName, "id")
    _ = println(s"Created table: $tableName")
    _ <- defaultManager.dynamoDb.putItem(tableName, Map(
      "id" -> AttributeValue.builder().s("user-001").build(),
      "name" -> AttributeValue.builder().s("John Doe").build(),
      "email" -> AttributeValue.builder().s("john@example.com").build()
    ))
    _ = println("Inserted item")
    item <- defaultManager.dynamoDb.getItem(tableName, Map(
      "id" -> AttributeValue.builder().s("user-001").build()
    ))
    _ = println(s"Retrieved item: ${item.map { case (k, v) => s"$k=${v.s()}" }.mkString(", ")}")
    allItems <- defaultManager.dynamoDb.scanTable(tableName)
    _ = println(s"Total items in table: ${allItems.size}")
    _ <- defaultManager.dynamoDb.deleteItem(tableName, Map(
      "id" -> AttributeValue.builder().s("user-001").build()
    ))
    _ = println("Deleted item")
    _ <- defaultManager.dynamoDb.deleteTable(tableName)
    _ = println(s"Deleted table: $tableName")
  } yield "DynamoDB workflow completed successfully"

  dynamoWorkflow match {
    case Success(msg) => println(msg)
    case Failure(ex) => println(s"DynamoDB workflow failed: ${ex.getMessage}")
  }

  // Cleanup
  defaultManager.shutdown()
  println("\n=== Demo Complete ===")
}